  contactPerson: true,
});

export const insertSalaryResearchSchema = createInsertSchema(salaryResearch).pick({
  jobTitle: true,
  location: true,
  experienceLevel: true,
  currentSalary: true,
  targetSalary: true,
  strengths: true,
  achievements: true,
  companySize: true,
  industry: true,
